SELECT device_id, model
FROM devices
WHERE operational_range_min BETWEEN 10 AND 15;

SELECT device_id, quantity, location, last_updated
FROM device_inventory
WHERE condition = 'good';

SELECT AVG(d.accuracy) AS average_accuracy
FROM devices d
JOIN device_inventory di ON d.device_id = di.device_id;

SELECT COUNT(device_id) AS total_devices
FROM devices
WHERE model LIKE 'DGP2-%';

SELECT device_id, last_updated
FROM device_inventory
ORDER BY last_updated DESC;

SELECT SUM(quantity) AS total_quantity
FROM device_inventory
WHERE location = 'Warehouse B';

SELECT model, operational_range_max
FROM devices
ORDER BY operational_range_max DESC;

SELECT DISTINCT device_id
FROM maintenance_records
WHERE maintenance_date >= date('now', '-6 months');

SELECT device_id, SUM(quantity) AS total_inventory
FROM device_inventory
GROUP BY device_id;

SELECT COUNT(device_id) AS actuator_count
FROM devices
WHERE actuator_type IS NOT NULL;

SELECT DISTINCT model
FROM devices
ORDER BY model;
